proof fn phi_4_write_seq_idle_plus_write_seq(mem: PTMem, writes: Seq<(usize, usize)>, addr: usize)
    requires
        forall|i| 0 <= i < writes.len() ==> (#[trigger] writes[i]).0 != addr,
        mem.mem.contains_key(addr),
    ensures
        mem.write_seq(writes).mem.contains_key(addr),
